## pages/Home.tsx

Implemented the **Visual Route Stepper**: A beautiful, scrolling horizontal timeline that connects the counties in the calculated route, replacing the simple text list.

```tsx
import React, { useEffect, useState, useMemo } from 'react';
import { AdCard } from '../components/AdCard';
import { Carousel, Slide } from '../components/Carousel';
import { CategoryNav } from '../components/CategoryNav';
import { fetchActiveAds } from '../services/mockBackend';
import { Ad } from '../types';
import { getCounties, getCities, getVillages } from '../data/locations';
import { getCountiesOnRoute } from '../utils/routeGraph';

interface HomeProps {
  onNavigate: (path: string) => void;
  onOpenCreateModal: () => void;
  onAdClick: (ad: Ad) => void;
  favoriteIds: string[];
  onToggleFavorite: (id: string) => void;
}

export const Home: React.FC<HomeProps> = ({ 
  onNavigate, 
  onOpenCreateModal, 
  onAdClick,
  favoriteIds,
  onToggleFavorite 
}) => {
  const [ads, setAds] = useState<Ad[]>([]);
  const [loading, setLoading] = useState(true);

  // Search Mode: 'local' (Standard) or 'route' (Travel)
  const [searchMode, setSearchMode] = useState<'local' | 'route'>('local');

  // Filters
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedCategory, setSelectedCategory] = useState('');
  const [showFavoritesOnly, setShowFavoritesOnly] = useState(false);

  // Local Mode State
  const [filterCounty, setFilterCounty] = useState('');
  const [filterCity, setFilterCity] = useState('');
  const [filterVillage, setFilterVillage] = useState('');
  const [availableCities, setAvailableCities] = useState<string[]>([]);
  const [availableVillages, setAvailableVillages] = useState<string[]>([]);

  // Route Mode State
  const [routeStartCounty, setRouteStartCounty] = useState('');
  const [routeStartCity, setRouteStartCity] = useState(''); 
  const [routeEndCounty, setRouteEndCounty] = useState('');
  const [routeEndCity, setRouteEndCity] = useState('');
  const [calculatedRouteCounties, setCalculatedRouteCounties] = useState<string[]>([]);

  // Route Dropdown Options
  const [startCities, setStartCities] = useState<string[]>([]);
  const [endCities, setEndCities] = useState<string[]>([]);

  useEffect(() => {
    const loadAds = async () => {
      try {
        const data = await fetchActiveAds();
        setAds(data);
      } catch (err) {
        console.error("Failed to load ads", err);
      } finally {
        setLoading(false);
      }
    };
    loadAds();
  }, []);

  // Cascading Filters (Local Mode)
  useEffect(() => {
    if (filterCounty) {
      setAvailableCities(getCities(filterCounty));
      setFilterCity('');
      setFilterVillage('');
      setAvailableVillages([]);
    } else {
      setAvailableCities([]);
      setFilterCity('');
      setFilterVillage('');
      setAvailableVillages([]);
    }
  }, [filterCounty]);

  useEffect(() => {
    if (filterCounty && filterCity) {
      setAvailableVillages(getVillages(filterCounty, filterCity));
      setFilterVillage('');
    } else {
      setAvailableVillages([]);
      setFilterVillage('');
    }
  }, [filterCounty, filterCity]);

  // Route Mode Cascading
  useEffect(() => {
    if (routeStartCounty) {
      setStartCities(getCities(routeStartCounty));
      setRouteStartCity('');
    } else {
      setStartCities([]);
    }
  }, [routeStartCounty]);

  useEffect(() => {
    if (routeEndCounty) {
      setEndCities(getCities(routeEndCounty));
      setRouteEndCity('');
    } else {
      setEndCities([]);
    }
  }, [routeEndCounty]);

  // Route Calculation
  useEffect(() => {
    if (searchMode === 'route' && routeStartCounty && routeEndCounty) {
      const path = getCountiesOnRoute(routeStartCounty, routeEndCounty);
      setCalculatedRouteCounties(path);
    } else {
      setCalculatedRouteCounties([]);
    }
  }, [searchMode, routeStartCounty, routeEndCounty]);

  // --- Filtering & Sorting Logic (Memoized) ---
  const processedAds = useMemo(() => {
    // 1. Filter
    const filtered = ads.filter(ad => {
      // Keyword
      const matchesSearch = 
        ad.title.toLowerCase().includes(searchTerm.toLowerCase()) || 
        ad.description.toLowerCase().includes(searchTerm.toLowerCase());

      // Category
      const matchesCategory = selectedCategory ? ad.category === selectedCategory : true;

      // Location
      const adLocation = ad.location || { county: '', city: '', village: '' };
      let matchesLocation = true;

      if (searchMode === 'local') {
        const matchesCounty = filterCounty ? adLocation.county === filterCounty : true;
        const matchesCity = filterCity ? adLocation.city === filterCity : true;
        const matchesVillage = filterVillage ? adLocation.village === filterVillage : true;
        matchesLocation = matchesCounty && matchesCity && matchesVillage;
      } else {
        // Route Mode: Include ALL ads in the calculated counties
        if (routeStartCounty && routeEndCounty && calculatedRouteCounties.length > 0) {
          matchesLocation = calculatedRouteCounties.includes(adLocation.county);
        }
      }

      // Favorites
      const matchesFavorite = showFavoritesOnly ? favoriteIds.includes(ad.id) : true;

      return matchesSearch && matchesCategory && matchesLocation && matchesFavorite;
    });

    // 2. Sort
    return filtered.sort((a, b) => {
      // Priority: Route Order (if in route mode)
      if (searchMode === 'route' && calculatedRouteCounties.length > 0) {
        const idxA = calculatedRouteCounties.indexOf(a.location.county);
        const idxB = calculatedRouteCounties.indexOf(b.location.county);

        // If counties are different, sort by position in route (Start -> End)
        if (idxA !== -1 && idxB !== -1 && idxA !== idxB) {
          return idxA - idxB;
        }
      }

      // Secondary: Date (Newest first)
      return b.createdAt - a.createdAt;
    });
  }, [
    ads, 
    searchTerm, 
    selectedCategory, 
    searchMode, 
    filterCounty, 
    filterCity, 
    filterVillage, 
    routeStartCounty, 
    routeEndCounty, 
    calculatedRouteCounties, 
    showFavoritesOnly, 
    favoriteIds
  ]);

  const heroSlides: Slide[] = [
    {
      id: '1',
      image: 'https://images.unsplash.com/photo-1488459716781-31db52582fe9?auto=format&fit=crop&q=80&w=2000',
      title: 'Support Local Producers',
      description: 'Discover fresh, handmade, and unique products directly from the source. Join MiculProducator today.',
      ctaText: 'Start Selling Now',
      onCtaClick: onOpenCreateModal,
    },
    {
      id: '2',
      image: 'https://images.unsplash.com/photo-1615485925763-867862780c10?auto=format&fit=crop&q=80&w=2000',
      title: 'Fresh from the Garden',
      description: 'Find seasonal vegetables, organic fruits, and artisanal foods right in your neighborhood.',
      ctaText: 'Browse Fresh Food',
      onCtaClick: () => {
        setSelectedCategory('Legume');
        document.getElementById('listings')?.scrollIntoView({ behavior: 'smooth' });
      },
    },
    {
      id: '3',
      image: 'https://images.unsplash.com/photo-1469854523086-cc02fe5d8800?auto=format&fit=crop&q=80&w=2000',
      title: 'Traveling across Romania?',
      description: 'Find fresh food and products along your route. Support locals wherever you go.',
      ctaText: 'Plan Route',
      onCtaClick: () => {
        setSearchMode('route');
        document.getElementById('listings')?.scrollIntoView({ behavior: 'smooth' });
      },
    }
  ];

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">

      {/* Header Carousel */}
      <Carousel slides={heroSlides} />

      {/* Visual Category Navigation */}
      <CategoryNav selectedCategory={selectedCategory} onSelectCategory={setSelectedCategory} />

      <div id="listings" className="mb-6">
        <div className="flex flex-col sm:flex-row justify-between items-end mb-6 gap-4">
           <div>
             <h1 className="text-3xl font-bold text-gray-900">Latest Listings</h1>
             <p className="text-gray-500 mt-1">Discover great deals or sell your items today.</p>
           </div>

           <div className="flex space-x-2">
            <button
               onClick={() => setShowFavoritesOnly(!showFavoritesOnly)}
               className={`flex items-center px-4 py-2 rounded-full border text-sm font-medium transition-colors ${
                  showFavoritesOnly 
                    ? 'bg-red-50 text-red-600 border-red-200' 
                    : 'bg-white text-gray-600 border-gray-300 hover:bg-gray-50'
               }`}
             >
               <svg className={`w-4 h-4 mr-2 ${showFavoritesOnly ? 'fill-current' : ''}`} fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" /></svg>
               {showFavoritesOnly ? 'Show All' : 'Show Favorites'}
             </button>
           </div>
        </div>

        {/* Search & Filter Bar */}
        <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
           {/* Mode Toggles */}
