## pages/AdDetails.tsx

Updated related ads logic to find matches based on *any* shared category and display the category list.

```tsx
import React, { useEffect, useState } from 'react';
import { fetchAdById, fetchActiveAds } from '../services/mockBackend';
import { Ad } from '../types';
import { Button } from '../components/Button';
import { AdCard } from '../components/AdCard';

interface AdDetailsProps {
  id: string;
  initialData?: Ad | null;
  onNavigate?: (path: string) => void;
  onClose?: () => void;
  isFavorite?: boolean;
  onToggleFavorite?: () => void;
  onAddToast?: (type: 'success' | 'info', msg: string) => void;
}

export const AdDetails: React.FC<AdDetailsProps> = ({ 
  id, 
  initialData, 
  onNavigate, 
  onClose,
  isFavorite,
  onToggleFavorite,
  onAddToast 
}) => {
  const [ad, setAd] = useState<Ad | null>(initialData || null);
  const [loading, setLoading] = useState(!initialData);
  const [currentImageIndex, setCurrentImageIndex] = useState(0);

  // Related Ads State
  const [relatedAds, setRelatedAds] = useState<Ad[]>([]);

  useEffect(() => {
    // If we received initial data, update local state, otherwise fetch
    if (initialData) {
        setAd(initialData);
    } else {
        const load = async () => {
          try {
            setLoading(true);
            const data = await fetchAdById(id);
            setAd(data);
          } catch (err) {
            console.error(err);
          } finally {
            setLoading(false);
          }
        };
        load();
    }
  }, [id, initialData]);

  // Fetch Related Ads when main Ad is loaded
  useEffect(() => {
    if (ad) {
      const loadRelated = async () => {
        try {
          const allAds = await fetchActiveAds();
          // Find ads that share AT LEAST ONE category with current ad
          const similar = allAds
            .filter(a => 
              a.id !== ad.id && 
              a.categories.some(cat => ad.categories.includes(cat))
            )
            .slice(0, 3); // Take top 3
          setRelatedAds(similar);
        } catch (e) {
          // ignore error for related
        }
      };
      loadRelated();
    }
  }, [ad]);

  // Handle switch to related ad
  const handleRelatedClick = (relatedAd: Ad) => {
    setAd(relatedAd);
    setCurrentImageIndex(0);
    // Logic to scroll to top would be nice, but simple state switch works
  };

  const nextImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (ad && ad.images.length > 0) {
      setCurrentImageIndex((prev) => (prev + 1) % ad.images.length);
    }
  };

  const prevImage = (e: React.MouseEvent) => {
    e.stopPropagation();
    if (ad && ad.images.length > 0) {
      setCurrentImageIndex((prev) => (prev - 1 + ad.images.length) % ad.images.length);
    }
  };

  const handleShare = async () => {
    const url = window.location.origin + `/#/ad/${id}`;
    if (navigator.share) {
      try {
        await navigator.share({
          title: ad?.title,
          text: `Check out this product on MiculProducator: ${ad?.title}`,
          url: url,
        });
      } catch (err) {
        // Share cancelled or failed
      }
    } else {
      await navigator.clipboard.writeText(url);
      if (onAddToast) onAddToast('info', 'Link copied to clipboard!');
    }
  };

  if (loading) return <div className="p-12 text-center text-gray-500">Loading ad details...</div>;
  if (!ad) return <div className="p-12 text-center text-red-500">Ad not found or removed.</div>;

  const whatsappLink = ad.phoneNumber 
    ? `https://wa.me/40${ad.phoneNumber.replace(/^0/, '')}?text=Salut, am vazut anuntul "${ad.title}" pe MiculProducator si sunt interesat.`
    : null;

  const hasMultipleImages = ad.images.length > 1;

  return (
    <div className="bg-white">
      {!onClose && onNavigate && (
        <div className="mb-4">
          <button onClick={() => onNavigate('/')} className="text-indigo-600 hover:text-indigo-800 text-sm flex items-center">
            <svg className="w-4 h-4 mr-1" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" /></svg>
            Back to listings
          </button>
        </div>
      )}

      <div className="overflow-hidden">
        {/* Image Gallery */}
        <div className="bg-gray-100 aspect-w-16 aspect-h-9 max-h-[400px] h-[300px] md:h-[400px] rounded-lg overflow-hidden mb-6 relative group select-none">
             {ad.images.length > 0 ? (
               <img 
                 src={ad.images[currentImageIndex]} 
                 alt={`${ad.title} - Image ${currentImageIndex + 1}`} 
                 className="w-full h-full object-contain bg-gray-900" 
               />
             ) : (
                <div className="flex items-center justify-center h-full text-gray-400">No Image</div>
             )}

             {/* Favorite & Share Overlay */}
             <div className="absolute top-2 right-2 z-10 flex space-x-2">
                 <button
                   onClick={() => onToggleFavorite && onToggleFavorite()}
                   className="p-2 rounded-full bg-white/90 text-gray-800 shadow-sm backdrop-blur-sm hover:bg-white transition-transform active:scale-95"
                 >
                   <svg 
                      className={`w-5 h-5 transition-colors ${isFavorite ? 'text-red-500 fill-current' : 'text-gray-400'}`} 
                      xmlns="http://www.w3.org/2000/svg" 
                      viewBox="0 0 24 24" 
                      fill="none" 
                      stroke="currentColor" 
                      strokeWidth="2" 
                      strokeLinecap="round" 
                      strokeLinejoin="round"
                    >
                      <path d="M20.84 4.61a5.5 5.5 0 0 0-7.78 0L12 5.67l-1.06-1.06a5.5 5.5 0 0 0-7.78 7.78l1.06 1.06L12 21.23l7.78-7.78 1.06-1.06a5.5 5.5 0 0 0 0-7.78z"></path>
                    </svg>
                 </button>
                 <button
                   onClick={handleShare}
                   className="p-2 rounded-full bg-white/90 text-gray-800 shadow-sm backdrop-blur-sm hover:bg-white transition-transform active:scale-95"
                 >
                   <svg className="w-5 h-5 text-indigo-600" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8.684 13.342C8.886 12.938 9 12.482 9 12c0-.482-.114-.938-.316-1.342m0 2.684a3 3 0 110-2.684m0 2.684l6.632 3.316m-6.632-6l6.632-3.316m0 0a3 3 0 105.367-2.684 3 3 0 00-5.367 2.684zm0 9.316a3 3 0 105.368 2.684 3 3 0 00-5.368-2.684z" /></svg>
                 </button>
             </div>

             {hasMultipleImages && (
               <>
                 <button 
                   onClick={prevImage}
                   className="absolute left-2 top-1/2 -translate-y-1/2 p-2 rounded-full bg-black/30 text-white hover:bg-black/50 backdrop-blur-sm transition-colors opacity-0 group-hover:opacity-100 focus:opacity-100"
                 >
                   <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 19l-7-7 7-7" /></svg>
                 </button>

                 <button 
                   onClick={nextImage}
                   className="absolute right-2 top-1/2 -translate-y-1/2 p-2 rounded-full bg-black/30 text-white hover:bg-black/50 backdrop-blur-sm transition-colors opacity-0 group-hover:opacity-100 focus:opacity-100"
                 >
                   <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 5l7 7-7 7" /></svg>
                 </button>

                 <div className="absolute bottom-4 left-1/2 -translate-x-1/2 flex space-x-2 z-10">
                   {ad.images.map((_, idx) => (
                     <button
                       key={idx}
                       onClick={() => setCurrentImageIndex(idx)}
                       className={`w-2 h-2 rounded-full transition-all duration-300 ${
                         idx === currentImageIndex ? 'bg-white w-4' : 'bg-white/50 hover:bg-white/80'
                       }`}
                     />
                   ))}
                 </div>
               </>
             )}
        </div>

        <div className="px-1 md:px-2">
          <div className="flex flex-col md:flex-row md:justify-between md:items-start gap-4">
            <div>
              <div className="flex items-center gap-2">
                <h1 className="text-2xl md:text-3xl font-bold text-gray-900 leading-tight">{ad.title}</h1>
                <span className="inline-flex items-center px-2 py-0.5 rounded text-xs font-medium bg-gray-100 text-gray-800">
                    ID: {ad.id.slice(0, 6)}
                </span>
              </div>

              <div className="mt-2 flex flex-wrap gap-2 mb-3">
                {ad.categories.map(cat => (
                  <span key={cat} className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800">
                    {cat}
                  </span>
                ))}
              </div>

              <div className="flex items-center text-sm text-gray-500">
                <svg className="w-4 h-4 mr-1 flex-shrink-0" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" /><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" /></svg>
                <span>
                   {ad.location.city}, {ad.location.county}
                   {ad.location.village && <span className="text-gray-400"> • {ad.location.village}</span>}
                </span>
                <span className="mx-2 text-gray-300">|</span>
                <span>{new Date(ad.createdAt).toLocaleDateString()}</span>
              </div>
            </div>
            <div className="flex-shrink-0">
               <span className="text-3xl font-bold text-green-600 block">{ad.price.toLocaleString()} <span className="text-lg text-green-700">RON</span></span>
            </div>
          </div>

          <div className="mt-8">
            <h3 className="text-sm font-medium text-gray-900 uppercase tracking-wider mb-2">Description</h3>
            <div className="prose prose-sm max-w-none text-gray-600 bg-gray-50 p-4 rounded-lg border border-gray-100">
              <p className="whitespace-pre-wrap leading-relaxed">{ad.description}</p>
            </div>
          </div>

          <div className="mt-8 border-t border-gray-100 pt-6">
             <div className="flex flex-col sm:flex-row gap-3">
                {whatsappLink ? (
                   <a 
                     href={whatsappLink}
                     target="_blank"
                     rel="noreferrer"
                     className="flex-1 inline-flex items-center justify-center px-6 py-3 border border-transparent text-base font-medium rounded-md shadow-sm text-white bg-[#25D366] hover:bg-[#128C7E] transition-colors focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-green-500"
                   >
                      <svg className="w-5 h-5 mr-2" fill="currentColor" viewBox="0 0 24 24"><path d="M.057 24l1.687-6.163c-1.041-1.804-1.588-3.849-1.587-5.946.003-6.556 5.338-11.891 11.893-11.891 3.181.001 6.167 1.24 8.413 3.488 2.245 2.248 3.481 5.236 3.48 8.414-.003 6.557-5.338 11.892-11.893 11.892-1.99-.001-3.951-.5-5.688-1.448l-6.305 1.654zm6.597-3.807c1.676.995 3.276 1.591 5.392 1.592 5.448 0 9.886-4.434 9.889-9.885.002-5.462-4.415-9.89-9.881-9.892-5.452 0-9.887 4.434-9.889 9.884-.001 2.225.651 3.891 1.746 5.634l-.999 3.648 3.742-.981zm11.387-5.464c-.074-.124-.272-.198-.57-.347-.297-.149-1.758-.868-2.031-.967-.272-.099-.47-.149-.669.149-.198.297-.768.967-.941 1.165-.173.198-.347.223-.644.074-.297-.149-1.255-.463-2.39-1.475-.883-.788-1.48-1.761-1.653-2.059-.173-.297-.018-.458.13-.606.134-.133.297-.347.446-.521.151-.172.2-.296.3-.495.099-.198.05-.372-.025-.521-.075-.148-.669-1.611-.916-2.206-.242-.579-.487-.501-.669-.51l-.57-.01c-.198 0-.52.074-.792.372-.272.297-1.04 1.016-1.04 2.479 0 1.462 1.065 2.875 1.213 3.074.149.198 2.096 3.2 5.077 4.487.709.306 1.262.489 1.694.626.712.226 1.36.194 1.871.118.571-.085 1.758-.719 2.006-1.413.248-.695.248-1.29.173-1.414z"/></svg>
                      Chat on WhatsApp
