          {/* Related Products Section */}
          {relatedAds.length > 0 && (
             <div className="mt-12 mb-4">
               <h3 className="text-lg font-bold text-gray-900 mb-4 border-b border-gray-100 pb-2">You might also like</h3>
               <div className="grid grid-cols-2 md:grid-cols-3 gap-4">
                  {relatedAds.map(related => (
                    <AdCard 
