export const fetchActiveAds = async (): Promise<Ad[]> => {
  await delay(50);
  const ads = getAdsFromStorage();

  if (ads.length === 0) {
    const seedAds = generateSeedAds();
    saveAdsToStorage(seedAds);
    return seedAds;
  }

  return ads.filter((ad) => ad.status === AdStatus.ACTIVE).sort((a, b) => b.createdAt - a.createdAt);
};

export const fetchAdById = async (id: string): Promise<Ad | null> => {
  await delay(50);
  const ads = getAdsFromStorage();
  return ads.find((ad) => ad.id === id) || null;
};

// --- Protected/Private API Simulations ---

export const createAd = async (payload: CreateAdPayload): Promise<{ adId: string; token: string; paymentUrl: string }> => {
  await delay(1000);

  const newId = crypto.randomUUID();
  const token = crypto.randomUUID().replace(/-/g, '') + crypto.randomUUID().replace(/-/g, '');

  let imageUrls: string[] = [];

  if (payload.images.length > 0) {
    try {
      const processed = await Promise.all(
        payload.images.slice(0, 3).map(file => processAndResizeImage(file))
      );
      imageUrls = processed;
    } catch (e) {
      console.error("Image processing failed", e);
      imageUrls = [`https://via.placeholder.com/400x300.png?text=Error`];
    }
  } else {
    imageUrls = [`https://via.placeholder.com/400x300.png?text=No+Image`];
  }

  const newAd: Ad = {
    id: newId,
    title: payload.title,
    description: payload.description,
    price: payload.price,
    categories: payload.categories, // Array of categories
    email: payload.email,
    phoneNumber: payload.phoneNumber,
    location: payload.location,
    images: imageUrls,
    token: token,
    status: AdStatus.PENDING,
    createdAt: Date.now(),
    expiresAt: null,
  };

  const ads = getAdsFromStorage();
  saveAdsToStorage([...ads, newAd]);

  return {
    adId: newId,
    token: token,
    paymentUrl: `mock-stripe-checkout`, 
  };
};

export const simulatePaymentSuccess = async (adId: string): Promise<void> => {
  await delay(1500);
  const ads = getAdsFromStorage();
  const updatedAds = ads.map(ad => {
    if (ad.id === adId) {
      return {
        ...ad,
        status: AdStatus.ACTIVE,
        expiresAt: Date.now() + (28 * 24 * 60 * 60 * 1000) // 28 days as per plan
      };
    }
    return ad;
  });
  saveAdsToStorage(updatedAds);
};

export const verifyManageToken = async (id: string, token: string): Promise<Ad | null> => {
  await delay(500);
  const ads = getAdsFromStorage();
  const ad = ads.find(a => a.id === id);
  if (ad && ad.token === token) {
    return ad;
  }
  return null;
};

export const updateAd = async (id: string, token: string, updates: Partial<Ad>): Promise<boolean> => {
  await delay(800);
  const ads = getAdsFromStorage();
  const index = ads.findIndex(a => a.id === id && a.token === token);

  if (index === -1) return false;

  const updatedAd = { ...ads[index], ...updates };
  ads[index] = updatedAd;
  saveAdsToStorage(ads);
  return true;
};

export const deleteAd = async (id: string, token: string): Promise<boolean> => {
  await delay(500);
  const ads = getAdsFromStorage();
  const filtered = ads.filter(a => !(a.id === id && a.token === token));

  if (filtered.length === ads.length) return false;

  saveAdsToStorage(filtered);
  return true;
};

