import React, { useEffect, useState } from 'react';
import { verifyManageToken, updateAd, deleteAd } from '../services/mockBackend';
import { Ad, AdStatus, PRODUCT_CATEGORIES } from '../types';
import { Button } from '../components/Button';
import { getCounties, getCities, getVillages } from '../data/locations';

interface ManageAdProps {
  id: string;
  token: string;
  onNavigate: (path: string) => void;
}

export const ManageAd: React.FC<ManageAdProps> = ({ id, token, onNavigate }) => {
  const [ad, setAd] = useState<Ad | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Edit State
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState('');
  const [editDesc, setEditDesc] = useState('');
  const [editPrice, setEditPrice] = useState('');
  const [editPhone, setEditPhone] = useState('');
  const [editCategories, setEditCategories] = useState<string[]>([]);

  // Location Edit State
  const [editCounty, setEditCounty] = useState('');
  const [editCity, setEditCity] = useState('');
  const [editVillage, setEditVillage] = useState('');
  const [availableCities, setAvailableCities] = useState<string[]>([]);
  const [availableVillages, setAvailableVillages] = useState<string[]>([]);

  const [saving, setSaving] = useState(false);

  useEffect(() => {
    const checkToken = async () => {
      try {
        const data = await verifyManageToken(id, token);
        if (data) {
          setAd(data);
          // Initialize form fields
          setEditTitle(data.title);
          setEditDesc(data.description);
          setEditPrice(String(data.price));
          setEditPhone(data.phoneNumber);
          setEditCategories(data.categories);
          setEditCounty(data.location.county);
          setEditCity(data.location.city);
          setEditVillage(data.location.village || '');
        } else {
          setError('Invalid or expired management link.');
        }
      } catch (err) {
        setError('System error verifying token.');
      } finally {
        setLoading(false);
      }
    };
    checkToken();
  }, [id, token]);

  // Handle Location Cascading during edit
  useEffect(() => {
    if (editCounty) {
      setAvailableCities(getCities(editCounty));
    } else {
      setAvailableCities([]);
    }
  }, [editCounty]);

  useEffect(() => {
    if (editCounty && editCity) {
      setAvailableVillages(getVillages(editCounty, editCity));
    } else {
      setAvailableVillages([]);
    }
  }, [editCounty, editCity]);

  const toggleCategory = (cat: string) => {
    // Allow user to change categories, but respect the limit of their original plan
    // We assume the length of the initial category array indicates their plan limit (1, 3, or 5)
    const maxCategories = ad ? Math.max(ad.categories.length, editCategories.length) : 5; 

    if (editCategories.includes(cat)) {
      setEditCategories(prev => prev.filter(c => c !== cat));
    } else {
      if (editCategories.length < maxCategories) {
        setEditCategories(prev => [...prev, cat]);
      } else {
        alert(`Your current plan is limited to ${maxCategories} categories.`);
      }
    }
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      const updates: Partial<Ad> = {
        title: editTitle,
        description: editDesc,
        price: Number(editPrice),
        phoneNumber: editPhone,
        categories: editCategories,
        location: {
          county: editCounty,
          city: editCity,
          village: editVillage || undefined
        }
      };

      const success = await updateAd(id, token, updates);

      if (success) {
        setAd(prev => prev ? ({ ...prev, ...updates }) : null);
        setIsEditing(false);
        alert("Ad updated successfully!");
      } else {
        alert('Update failed. Please try again.');
      }
    } catch (e) {
      alert('Error updating ad.');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    if (!confirm("Are you sure you want to delete this ad? This cannot be undone.")) return;
    setSaving(true);
    try {
      await deleteAd(id, token);
      onNavigate('/');
    } catch (e) {
      alert("Failed to delete");
      setSaving(false);
    }
  };

  const handleRenew = () => {
     alert("Redirecting to Stripe for renewal payment... (Demo Only)");
  };

  if (loading) return <div className="p-8 text-center">Verifying access...</div>;
  if (error) return (
    <div className="p-8 text-center">
      <div className="bg-red-50 text-red-700 p-4 rounded-md inline-block">
        {error}
      </div>
      <div className="mt-4">
        <Button onClick={() => onNavigate('/')} variant="outline">Go Home</Button>
      </div>
    </div>
  );

  if (!ad) return null;

  return (
    <div className="max-w-4xl mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-2xl font-bold text-gray-900">Manage Listing</h1>
        <span className={`px-3 py-1 rounded-full text-sm font-medium ${
          ad.status === AdStatus.ACTIVE ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'
        }`}>
          {ad.status.toUpperCase()}
        </span>
      </div>

      <div className="bg-white shadow rounded-lg overflow-hidden border border-gray-200">
        <div className="p-6 border-b border-gray-200 bg-gray-50 flex justify-between items-center flex-wrap gap-4">
           <div>
             <h2 className="text-lg font-medium text-gray-900">Ad Details</h2>
             <p className="text-sm text-gray-500">Expires: {ad.expiresAt ? new Date(ad.expiresAt).toLocaleDateString() : 'Pending'}</p>
           </div>
           <div className="space-x-2">
             {!isEditing ? (
               <Button variant="secondary" onClick={() => setIsEditing(true)}>Edit Details</Button>
             ) : (
               <Button variant="outline" onClick={() => setIsEditing(false)}>Cancel Edit</Button>
             )}
             <Button variant="danger" onClick={handleDelete} isLoading={saving}>Delete Ad</Button>
           </div>
        </div>

        <div className="p-6 space-y-6">
          {isEditing ? (
            <div className="space-y-6">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Title</label>
                  <input 
                    type="text" 
                    value={editTitle} 
                    onChange={e => setEditTitle(e.target.value)} 
                    className="w-full border-gray-300 rounded-md shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border" 
                  />
                 </div>
                 <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Price (RON)</label>
                  <input 
                    type="number" 
                    value={editPrice} 
                    onChange={e => setEditPrice(e.target.value)} 
                    className="w-full border-gray-300 rounded-md shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border" 
                  />
                 </div>
               </div>

               <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Categories (Max based on plan)</label>
                  <div className="flex flex-wrap gap-2">
                    {PRODUCT_CATEGORIES.map((cat) => {
                      const isSelected = editCategories.includes(cat);
                      return (
                        <button
                          key={cat}
                          type="button"
                          onClick={() => toggleCategory(cat)}
                          className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${
                            isSelected 
                              ? 'bg-indigo-600 text-white border-indigo-600 shadow-sm' 
                              : 'bg-white text-gray-700 border-gray-300 hover:border-indigo-300 hover:bg-gray-50'
                          }`}
                        >
                          {cat} {isSelected && '✓'}
                        </button>
                      );
                    })}
                  </div>
               </div>

               <div className="grid grid-cols-1 md:grid-cols-3 gap-4 bg-gray-50 p-4 rounded-lg border border-gray-100">
                 <div>
                   <label className="block text-xs font-bold text-gray-500 uppercase mb-1">County</label>
                   <select 
                      value={editCounty} 
                      onChange={e => {
                        setEditCounty(e.target.value);
                        setEditCity('');
                        setEditVillage('');
                      }} 
                      className="w-full border-gray-300 rounded-md text-sm p-2"
                   >
                     {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
                   </select>
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-gray-500 uppercase mb-1">City/Commune</label>
                   <select 
                      value={editCity} 
                      onChange={e => {
                        setEditCity(e.target.value);
                        setEditVillage('');
                      }}
                      disabled={!editCounty}
                      className="w-full border-gray-300 rounded-md text-sm p-2 disabled:bg-gray-100"
                   >
                     <option value="">Select...</option>
                     {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                   </select>
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Village (Sat)</label>
                   <select 
                      value={editVillage} 
                      onChange={e => setEditVillage(e.target.value)}
                      disabled={!editCity}
                      className="w-full border-gray-300 rounded-md text-sm p-2 disabled:bg-gray-100"
                   >
                     <option value="">Select...</option>
                     {availableVillages.map(v => <option key={v} value={v}>{v}</option>)}
                   </select>
                 </div>
               </div>

               <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Phone Number</label>
                <input 
                  type="text" 
                  value={editPhone} 
                  onChange={e => setEditPhone(e.target.value)} 
                  className="w-full border-gray-300 rounded-md shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border" 
                />
               </div>

               <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                <textarea 
                  rows={5} 
                  value={editDesc} 
                  onChange={e => setEditDesc(e.target.value)} 
                  className="w-full border-gray-300 rounded-md shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border" 
                />
               </div>

               <div className="flex justify-end space-x-3 pt-4 border-t border-gray-100">
                 <Button variant="outline" onClick={() => setIsEditing(false)}>Cancel</Button>
                 <Button onClick={handleSave} isLoading={saving}>Save Changes</Button>
               </div>
            </div>
          ) : (
            <div className="space-y-6">
              <div className="flex flex-col md:flex-row gap-6">
                 {/* Left Column: Image (Preview) */}
                 <div className="w-full md:w-1/3">
                    <div className="aspect-w-4 aspect-h-3 rounded-lg overflow-hidden bg-gray-100 border border-gray-200">
                      {ad.images[0] ? (
                        <img src={ad.images[0]} alt="Ad" className="object-cover w-full h-full" />
                      ) : (
                        <div className="flex items-center justify-center h-48 text-gray-400">No Image</div>
                      )}
                    </div>
                 </div>

                 {/* Right Column: Details */}
                 <div className="w-full md:w-2/3 space-y-4">
                    <div className="flex justify-between items-start">
                       <div>
                          <h3 className="text-xl font-bold text-gray-900">{ad.title}</h3>
                          <p className="text-2xl font-bold text-green-600 mt-1">{ad.price} RON</p>
                       </div>
                    </div>

                    <div className="flex flex-wrap gap-2">
                      {ad.categories.map(cat => (
                        <span key={cat} className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800">
                          {cat}
                        </span>
                      ))}
                    </div>

                    <div className="grid grid-cols-2 gap-4 text-sm text-gray-600 bg-gray-50 p-3 rounded-lg">
                       <div>
                         <span className="block text-xs font-bold text-gray-400 uppercase">Location</span>
                         {ad.location.city}, {ad.location.county} {ad.location.village && `(${ad.location.village})`}
                       </div>
                       <div>
                         <span className="block text-xs font-bold text-gray-400 uppercase">Contact</span>
                         {ad.phoneNumber}
                       </div>
                    </div>

                    <div>
                       <span className="block text-xs font-bold text-gray-400 uppercase mb-1">Description</span>
                       <p className="text-gray-700 whitespace-pre-wrap">{ad.description}</p>
                    </div>
                 </div>
              </div>
            </div>
          )}
        </div>

        <div className="bg-gray-50 px-6 py-4 border-t border-gray-200">
           <div className="flex items-center justify-between">
             <div className="text-sm text-gray-600">
               <span className="block font-medium">Boost your visibility?</span>
               Extend your ad duration or promote it to the homepage.
             </div>
             <Button variant="outline" onClick={handleRenew}>Renew Plan</Button>
           </div>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef } from 'react';
import { Button } from '../components/Button';
import { createAd, simulatePaymentSuccess } from '../services/mockBackend';
import { getCounties, getCities, getVillages } from '../data/locations';
import { PRODUCT_CATEGORIES } from '../types';

interface CreateAdProps {
  onNavigate: (path: string) => void;
  onClose?: () => void;
}

interface Plan {
  id: 'basic' | 'standard' | 'premium';
  name: string;
  productCount: number;
  price: number;
  duration: number; // days
  features: string[];
  color: string;
}

const PLANS: Plan[] = [
  {
    id: 'basic',
    name: 'Starter',
    productCount: 1,
    price: 10,
    duration: 28,
    features: ['Sell 1 type of product', 'Visible in 1 Category', '28 Days Validity'],
    color: 'bg-blue-50 border-blue-200 text-blue-700'
  },
  {
    id: 'standard',
    name: 'Grower',
    productCount: 3,
    price: 20,
    duration: 28,
    features: ['Sell up to 3 types of products', 'Visible in 3 Categories', '28 Days Validity', 'Recommended'],
    color: 'bg-indigo-50 border-indigo-200 text-indigo-700'
  },
  {
    id: 'premium',
    name: 'Pro Market',
    productCount: 5,
    price: 30,
    duration: 28,
    features: ['Sell up to 5 types of products', 'Visible in 5 Categories', '28 Days Validity', 'Priority Support'],
    color: 'bg-purple-50 border-purple-200 text-purple-700'
  }
];

export const CreateAd: React.FC<CreateAdProps> = ({ onNavigate, onClose }) => {
  const [step, setStep] = useState<'plan' | 'form' | 'payment' | 'success'>('plan');
  const [loading, setLoading] = useState(false);

  // Plan State
  const [selectedPlan, setSelectedPlan] = useState<Plan | null>(null);

  // Form State
  const [title, setTitle] = useState('');
  const [selectedCategories, setSelectedCategories] = useState<string[]>([]);
  const [price, setPrice] = useState('');
  const [description, setDescription] = useState('');
  const [email, setEmail] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [images, setImages] = useState<File[]>([]);
  const [previews, setPreviews] = useState<string[]>([]);

  // Location State
  const [county, setCounty] = useState('');
  const [city, setCity] = useState('');
  const [village, setVillage] = useState('');

  // Location Dropdown Options
  const [availableCities, setAvailableCities] = useState<string[]>([]);
  const [availableVillages, setAvailableVillages] = useState<string[]>([]);

  // Cascading Dropdown Logic
  useEffect(() => {
    if (county) {
      setAvailableCities(getCities(county));
      setCity('');
      setVillage('');
      setAvailableVillages([]);
    } else {
      setAvailableCities([]);
    }
  }, [county]);

  useEffect(() => {
    if (county && city) {
      setAvailableVillages(getVillages(county, city));
      setVillage('');
    } else {
      setAvailableVillages([]);
    }
  }, [county, city]);

  // Creation Result
  const [createdAdData, setCreatedAdData] = useState<{ adId: string; token: string } | null>(null);

  const handleFileChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (e.target.files && e.target.files.length > 0) {
      const newFiles: File[] = Array.from(e.target.files);
      setImages(prev => [...prev, ...newFiles]);

      // Create previews
      const newPreviews = newFiles.map(file => URL.createObjectURL(file));
      setPreviews(prev => [...prev, ...newPreviews]);
    }
  };

  const removeImage = (index: number) => {
    setImages(prev => prev.filter((_, i) => i !== index));
    setPreviews(prev => {
      if (prev[index]) URL.revokeObjectURL(prev[index]);
      return prev.filter((_, i) => i !== index);
    });
  };

  // Category Toggle Logic
  const toggleCategory = (cat: string) => {
    if (!selectedPlan) return;

    if (selectedCategories.includes(cat)) {
      setSelectedCategories(prev => prev.filter(c => c !== cat));
    } else {
      if (selectedCategories.length < selectedPlan.productCount) {
        setSelectedCategories(prev => [...prev, cat]);
      } else {
        alert(`You can only select ${selectedPlan.productCount} categories with the ${selectedPlan.name} plan.`);
      }
    }
  };

  // Keep ref in sync for cleanup
  const previewsRef = useRef<string[]>([]);
  useEffect(() => {
    previewsRef.current = previews;
  }, [previews]);

  useEffect(() => {
    return () => {
      previewsRef.current.forEach(url => URL.revokeObjectURL(url));
    };
  }, []);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (selectedCategories.length === 0) {
      alert("Please select at least one category.");
      return;
    }
    setLoading(true);

    try {
      const result = await createAd({
        title,
        description,
        categories: selectedCategories,
        price: Number(price),
        email,
        phoneNumber,
        location: {
          county,
          city,
          village: village || undefined
        },
        images,
      });
      setCreatedAdData({ adId: result.adId, token: result.token });
      setStep('payment');
    } catch (error) {
      console.error(error);
      alert('Failed to create ad.');
    } finally {
      setLoading(false);
    }
  };

  const handleSimulatePayment = async () => {
    if (!createdAdData) return;
    setLoading(true);
    try {
      await simulatePaymentSuccess(createdAdData.adId);
      setStep('success');
    } catch (error) {
      alert('Payment failed simulation');
    } finally {
      setLoading(false);
    }
  };

  const handleCloseOrNavigate = () => {
    if (onClose) {
      onClose();
    } else {
      onNavigate('/');
    }
  };

  if (step === 'success' && createdAdData) {
    const manageLink = `/manage?id=${createdAdData.adId}&token=${createdAdData.token}`;
    const fullManageLink = `${window.location.origin}/#${manageLink}`;

    return (
      <div className="px-4 py-8 text-center animate-fade-in">
        <div className="mx-auto flex items-center justify-center h-16 w-16 rounded-full bg-green-100 mb-6">
          <svg className="h-8 w-8 text-green-600" fill="none" viewBox="0 0 24 24" stroke="currentColor">
            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" />
          </svg>
        </div>
        <h2 className="text-2xl font-bold text-gray-900 mb-2">Ad Published Successfully!</h2>
        <p className="text-gray-500 mb-8">
          Your ad is now active.
        </p>

        <div className="bg-blue-50 border border-blue-200 rounded-lg p-6 text-left mb-8">
          <div className="flex items-start mb-4">
            <div className="flex-shrink-0">
               <svg className="h-6 w-6 text-blue-600" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M13 16h-1v-4h-1m1-4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
            </div>
            <div className="ml-3">
              <h3 className="text-sm font-bold text-blue-800 uppercase tracking-wide">Important: Save Your Edit Link</h3>
              <p className="text-sm text-blue-700 mt-1">
                You do not have an account. To edit or delete your ad later, you <strong>must save this link</strong>.
              </p>
            </div>
          </div>

          <div className="flex flex-col space-y-3">
            <div className="relative rounded-md shadow-sm">
              <input
                type="text"
                readOnly
                value={fullManageLink}
                className="block w-full rounded-md border-gray-300 pr-10 focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-3 bg-white font-mono text-gray-600"
                onClick={(e) => e.currentTarget.select()}
              />
            </div>
            <Button 
              variant="secondary" 
              onClick={() => {
                navigator.clipboard.writeText(fullManageLink);
                alert("Link copied to clipboard!");
              }}
              className="w-full justify-center"
            >
              <svg className="w-4 h-4 mr-2" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M8 5H6a2 2 0 00-2 2v12a2 2 0 002 2h10a2 2 0 002-2v-1M8 5a2 2 0 002 2h2a2 2 0 002-2M8 5a2 2 0 012-2h2a2 2 0 012 2m0 0h2a2 2 0 012 2v3m2 4H10m0 0l3-3m-3 3l3 3" /></svg>
              Copy Link to Clipboard
            </Button>
          </div>
        </div>

        <div className="flex justify-center flex-col gap-3">
           <Button 
              variant="primary" 
              onClick={() => {
                onNavigate(manageLink);
                if (onClose) onClose();
              }}
            >
              Go to Management Page Now
            </Button>
            <Button variant="outline" onClick={handleCloseOrNavigate}>
              Close & Go Home
            </Button>
        </div>
      </div>
    );
  }

  if (step === 'payment') {
    return (
      <div className="px-4 py-8 text-center animate-fade-in">
        <h2 className="text-xl font-bold text-gray-900 mb-4">Complete Payment</h2>
        <p className="text-gray-500 mb-8">
          You selected the <strong>{selectedPlan?.name}</strong> plan.
        </p>

        <div className="bg-white p-6 rounded-lg shadow-sm border border-gray-200 mb-8 text-left">
          <div className="flex justify-between items-center mb-4">
            <span className="text-gray-600">Plan: {selectedPlan?.name} ({selectedPlan?.duration} Days)</span>
            <span className="font-bold text-gray-900">{selectedPlan?.price.toFixed(2)} RON</span>
          </div>
          <div className="flex justify-between items-center border-t pt-4">
            <span className="font-bold text-gray-900">Total</span>
            <span className="font-bold text-2xl text-indigo-600">{selectedPlan?.price.toFixed(2)} RON</span>
          </div>
        </div>

        <Button 
          isLoading={loading} 
          onClick={handleSimulatePayment} 
          className="w-full h-12 text-lg"
        >
          Pay securely with Stripe
        </Button>
        <p className="text-xs text-gray-400 mt-4">This is a demo. No real money will be charged.</p>
      </div>
    );
  }

  if (step === 'plan') {
    return (
      <div className="w-full">
        {!onClose && (
          <div className="mb-8 text-center">
            <h1 className="text-3xl font-bold text-gray-900">Select a Plan</h1>
            <p className="text-gray-500 mt-2">Choose how many products/categories you want to list.</p>
          </div>
        )}

        <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mt-6">
          {PLANS.map(plan => (
            <div 
              key={plan.id}
              onClick={() => {
                setSelectedPlan(plan);
                setStep('form');
              }}
              className={`relative border-2 rounded-xl p-6 cursor-pointer transition-all duration-200 hover:shadow-lg hover:-translate-y-1 ${plan.color.replace('text-', 'border-').replace('bg-', 'hover:bg-')} bg-white`}
            >
              <div className="text-center">
                <h3 className="text-lg font-bold text-gray-900">{plan.name}</h3>
                <div className="mt-4 flex items-baseline justify-center text-gray-900">
                  <span className="text-4xl font-extrabold tracking-tight">{plan.price}</span>
                  <span className="ml-1 text-xl font-semibold">RON</span>
                </div>
                <p className="mt-1 text-sm text-gray-500">for {plan.duration} days</p>
              </div>
              <ul className="mt-6 space-y-4">
                {plan.features.map((feature, idx) => (
                  <li key={idx} className="flex items-start">
                    <div className="flex-shrink-0">
                      <svg className="h-5 w-5 text-green-500" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M5 13l4 4L19 7" /></svg>
                    </div>
                    <p className="ml-3 text-sm text-gray-700">{feature}</p>
                  </li>
                ))}
              </ul>
              <div className="mt-8">
                <div className="block w-full bg-indigo-600 border border-transparent rounded-md py-2 text-sm font-semibold text-white text-center hover:bg-indigo-700 transition-colors">
                  Select Plan
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  return (
    <div className="w-full">
      {/* If not in a modal, show the H1 */}
      {!onClose && (
        <div className="mb-8">
          <h1 className="text-3xl font-bold text-gray-900">Create New Ad</h1>
          <p className="text-gray-500 mt-2">Fill out the details below to list your items.</p>
        </div>
      )}

      <div className="mb-6 flex items-center justify-between bg-indigo-50 p-3 rounded-lg border border-indigo-100">
        <div>
          <span className="text-xs font-bold text-indigo-800 uppercase tracking-wide">Current Plan</span>
          <p className="text-sm font-semibold text-indigo-900">{selectedPlan?.name} ({selectedPlan?.productCount} Categories)</p>
        </div>
        <button onClick={() => { setStep('plan'); setSelectedCategories([]); }} className="text-xs text-indigo-600 hover:text-indigo-800 underline">
          Change Plan
        </button>
      </div>

      <form onSubmit={handleSubmit} className="space-y-6">
        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Ad Title</label>
          <input
            type="text"
            required
            value={title}
            onChange={(e) => setTitle(e.target.value)}
            className="block w-full rounded-md border-gray-300 border shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5"
            placeholder="e.g. Coș cu legume proaspete"
          />
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">
            Categories 
            <span className="ml-2 text-xs font-normal text-gray-500">
              (Select up to {selectedPlan?.productCount})
            </span>
          </label>
          <div className="flex flex-wrap gap-2">
            {PRODUCT_CATEGORIES.map((cat) => {
              const isSelected = selectedCategories.includes(cat);
              return (
                <button
                  key={cat}
                  type="button"
                  onClick={() => toggleCategory(cat)}
                  className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${
                    isSelected 
                      ? 'bg-indigo-600 text-white border-indigo-600 shadow-sm' 
                      : 'bg-white text-gray-700 border-gray-300 hover:border-indigo-300 hover:bg-gray-50'
                  }`}
                >
                  {cat} {isSelected && '✓'}
                </button>
              );
            })}
          </div>
          <p className="text-xs text-gray-500 mt-2">
            Selected: {selectedCategories.length} / {selectedPlan?.productCount}
          </p>
        </div>

        {/* Location Section */}
        <div className="border-t border-gray-100 pt-6">
          <h3 className="text-md font-medium text-gray-900 mb-4">Location (Romania)</h3>
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">

            {/* County Select */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Județ (County)</label>
              <select
                required
                value={county}
                onChange={(e) => setCounty(e.target.value)}
                className="block w-full rounded-md border-gray-300 border shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5 bg-white"
              >
                <option value="">Select Județ</option>
                {getCounties().map((c) => (
                  <option key={c} value={c}>{c}</option>
                ))}
              </select>
            </div>

            {/* City Select */}
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Oraș / Comună</label>
              <select
                required
                value={city}
                onChange={(e) => setCity(e.target.value)}
                disabled={!county}
                className="block w-full rounded-md border-gray-300 border shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5 bg-white disabled:bg-gray-100 disabled:text-gray-400"
              >
                <option value="">Select Oraș/Comună</option>
                {availableCities.map((c) => (
                  <option key={c} value={c}>{c}</option>
                ))}
              </select>
            </div>

            {/* Village Select */}
            <div className="sm:col-span-2">
              <label className="block text-sm font-medium text-gray-700 mb-1">Sat (Optional)</label>
               <select
                value={village}
                onChange={(e) => setVillage(e.target.value)}
                disabled={!city || availableVillages.length === 0}
                className="block w-full rounded-md border-gray-300 border shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5 bg-white disabled:bg-gray-100 disabled:text-gray-400"
              >
                <option value="">Select Sat (Optional)</option>
                {availableVillages.map((v) => (
                  <option key={v} value={v}>{v}</option>
                ))}
              </select>
              {availableVillages.length === 0 && city && (
                 <p className="text-xs text-gray-400 mt-1">No villages recorded for this location.</p>
              )}
            </div>
          </div>
        </div>

        <div className="border-t border-gray-100 pt-6">
          <h3 className="text-md font-medium text-gray-900 mb-4">Details</h3>
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2">
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Price (RON)</label>
              <input
                type="number"
                required
                min="0"
                value={price}
                onChange={(e) => setPrice(e.target.value)}
                className="block w-full rounded-md border-gray-300 border shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5"
                placeholder="0.00"
              />
            </div>
          </div>
          <div className="grid grid-cols-1 gap-4 sm:grid-cols-2 mt-4">
             <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Email Address (Private)</label>
              <input
                type="email"
                required
                value={email}
                onChange={(e) => setEmail(e.target.value)}
                className="block w-full rounded-md border-gray-300 border shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5"
                placeholder="For management link"
              />
              <p className="text-xs text-gray-400 mt-1">We'll send your management link here.</p>
            </div>
            <div>
              <label className="block text-sm font-medium text-gray-700 mb-1">Phone Number (Public)</label>
              <input
                type="tel"
                required
                value={phoneNumber}
                onChange={(e) => setPhoneNumber(e.target.value)}
                className="block w-full rounded-md border-gray-300 border shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5"
                placeholder="07XX XXX XXX"
              />
              <p className="text-xs text-gray-400 mt-1">Buyers will contact you via WhatsApp.</p>
            </div>
          </div>
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-2">Images</label>

          <div className="relative group flex justify-center px-6 pt-5 pb-6 border-2 border-gray-300 border-dashed rounded-md hover:bg-gray-50 hover:border-indigo-400 transition-all cursor-pointer">
            <input 
               type="file" 
               multiple 
               className="absolute inset-0 w-full h-full opacity-0 cursor-pointer z-10" 
               onChange={handleFileChange} 
               accept="image/*" 
            />
            <div className="space-y-1 text-center pointer-events-none">
              <svg className="mx-auto h-12 w-12 text-gray-400 group-hover:text-indigo-500 transition-colors" stroke="currentColor" fill="none" viewBox="0 0 48 48" aria-hidden="true">
                <path d="M28 8H12a4 4 0 00-4 4v20m32-12v8m0 0v8a4 4 0 01-4 4H12a4 4 0 01-4-4v-4m32-4l-3.172-3.172a4 4 0 00-5.656 0L28 28M8 32l9.172-9.172a4 4 0 015.656 0L28 28m0 0l4 4m4-24h8m-4-4v8m-12 4h.02" strokeWidth={2} strokeLinecap="round" strokeLinejoin="round" />
              </svg>
              <div className="flex text-sm text-gray-600 justify-center">
                <span className="relative rounded-md font-medium text-indigo-600 group-hover:text-indigo-500">
                  Upload files
                </span>
                <p className="pl-1">or drag and drop</p>
              </div>
              <p className="text-xs text-gray-500">PNG, JPG, GIF up to 5MB</p>
            </div>
          </div>

          {/* Previews Grid */}
          {previews.length > 0 && (
            <div className="grid grid-cols-3 gap-4 mt-4">
               {previews.map((src, idx) => (
                  <div key={idx} className="relative aspect-w-1 aspect-h-1 w-full overflow-hidden rounded-lg bg-gray-100 border border-gray-200 group">
                      <img src={src} alt={`Preview ${idx}`} className="object-cover w-full h-full" />
                      <button 
                         type="button"
                         onClick={() => removeImage(idx)}
                         className="absolute top-1 right-1 bg-white/90 text-red-600 rounded-full p-1 shadow-sm opacity-0 group-hover:opacity-100 transition-opacity hover:bg-white"
                         title="Remove image"
                      >
                         <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" /></svg>
                      </button>
                  </div>
               ))}
            </div>
          )}
        </div>

        <div>
          <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
          <textarea
            required
            rows={4}
            value={description}
            onChange={(e) => setDescription(e.target.value)}
            className="block w-full rounded-md border-gray-300 border shadow-sm focus:border-indigo-500 focus:ring-indigo-500 sm:text-sm p-2.5"
            placeholder="Describe your products..."
          />
        </div>

        <div className="flex justify-end pt-4 border-t border-gray-100">
          <Button type="button" variant="outline" className="mr-3" onClick={handleCloseOrNavigate}>
            Cancel
          </Button>
          <Button type="submit" isLoading={loading}>
            Proceed to Payment
          </Button>
        </div>
      </form>
    </div>
  );
};

import React, { useEffect, useState } from 'react';
import { verifyManageToken, updateAd, deleteAd } from '../services/mockBackend';
import { Ad, AdStatus, PRODUCT_CATEGORIES } from '../types';
import { Button } from '../components/Button';
import { getCounties, getCities, getVillages } from '../data/locations';

interface ManageAdProps {
  id: string;
  token: string;
  onNavigate: (path: string) => void;
}

export const ManageAd: React.FC<ManageAdProps> = ({ id, token, onNavigate }) => {
  const [ad, setAd] = useState<Ad | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  // Edit State
  const [isEditing, setIsEditing] = useState(false);
  const [editTitle, setEditTitle] = useState('');
  const [editDesc, setEditDesc] = useState('');
  const [editPrice, setEditPrice] = useState('');
  const [editPhone, setEditPhone] = useState('');
  const [editCategories, setEditCategories] = useState<string[]>([]);

  // Location Edit State
  const [editCounty, setEditCounty] = useState('');
  const [editCity, setEditCity] = useState('');
  const [editVillage, setEditVillage] = useState('');
  const [availableCities, setAvailableCities] = useState<string[]>([]);
  const [availableVillages, setAvailableVillages] = useState<string[]>([]);

  const [saving, setSaving] = useState(false);

  useEffect(() => {
    const checkToken = async () => {
      try {
        const data = await verifyManageToken(id, token);
        if (data) {
          setAd(data);
          // Initialize form fields
          setEditTitle(data.title);
          setEditDesc(data.description);
          setEditPrice(String(data.price));
          setEditPhone(data.phoneNumber);
          setEditCategories(data.categories);
          setEditCounty(data.location.county);
          setEditCity(data.location.city);
          setEditVillage(data.location.village || '');
        } else {
          setError('Invalid or expired management link.');
        }
      } catch (err) {
        setError('System error verifying token.');
      } finally {
        setLoading(false);
      }
    };
    checkToken();
  }, [id, token]);

  // Handle Location Cascading during edit
  useEffect(() => {
    if (editCounty) {
      setAvailableCities(getCities(editCounty));
    } else {
      setAvailableCities([]);
    }
  }, [editCounty]);

  useEffect(() => {
    if (editCounty && editCity) {
      setAvailableVillages(getVillages(editCounty, editCity));
    } else {
      setAvailableVillages([]);
    }
  }, [editCounty, editCity]);

  const toggleCategory = (cat: string) => {
    // Allow user to change categories, but respect the limit of their original plan
    // We assume the length of the initial category array indicates their plan limit (1, 3, or 5)
    const maxCategories = ad ? Math.max(ad.categories.length, editCategories.length) : 5; 

    if (editCategories.includes(cat)) {
      setEditCategories(prev => prev.filter(c => c !== cat));
    } else {
      if (editCategories.length < maxCategories) {
        setEditCategories(prev => [...prev, cat]);
      } else {
        alert(`Your current plan is limited to ${maxCategories} categories.`);
      }
    }
  };

  const handleSave = async () => {
    setSaving(true);
    try {
      const updates: Partial<Ad> = {
        title: editTitle,
        description: editDesc,
        price: Number(editPrice),
        phoneNumber: editPhone,
        categories: editCategories,
        location: {
          county: editCounty,
          city: editCity,
          village: editVillage || undefined
        }
      };

      const success = await updateAd(id, token, updates);

      if (success) {
        setAd(prev => prev ? ({ ...prev, ...updates }) : null);
        setIsEditing(false);
        alert("Ad updated successfully!");
      } else {
        alert('Update failed. Please try again.');
      }
    } catch (e) {
      alert('Error updating ad.');
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async () => {
    if (!confirm("Are you sure you want to delete this ad? This cannot be undone.")) return;
    setSaving(true);
    try {
      await deleteAd(id, token);
      onNavigate('/');
    } catch (e) {
      alert("Failed to delete");
      setSaving(false);
    }
  };

  const handleRenew = () => {
     alert("Redirecting to Stripe for renewal payment... (Demo Only)");
  };

  if (loading) return <div className="p-8 text-center">Verifying access...</div>;
  if (error) return (
    <div className="p-8 text-center">
      <div className="bg-red-50 text-red-700 p-4 rounded-md inline-block">
        {error}
      </div>
      <div className="mt-4">
        <Button onClick={() => onNavigate('/')} variant="outline">Go Home</Button>
      </div>
    </div>
  );

  if (!ad) return null;

  return (
    <div className="max-w-4xl mx-auto px-4 py-8">
      <div className="flex justify-between items-center mb-8">
        <h1 className="text-2xl font-bold text-gray-900">Manage Listing</h1>
        <span className={`px-3 py-1 rounded-full text-sm font-medium ${
          ad.status === AdStatus.ACTIVE ? 'bg-green-100 text-green-800' : 'bg-yellow-100 text-yellow-800'
        }`}>
          {ad.status.toUpperCase()}
        </span>
      </div>

      <div className="bg-white shadow rounded-lg overflow-hidden border border-gray-200">
        <div className="p-6 border-b border-gray-200 bg-gray-50 flex justify-between items-center flex-wrap gap-4">
           <div>
             <h2 className="text-lg font-medium text-gray-900">Ad Details</h2>
             <p className="text-sm text-gray-500">Expires: {ad.expiresAt ? new Date(ad.expiresAt).toLocaleDateString() : 'Pending'}</p>
           </div>
           <div className="space-x-2">
             {!isEditing ? (
               <Button variant="secondary" onClick={() => setIsEditing(true)}>Edit Details</Button>
             ) : (
               <Button variant="outline" onClick={() => setIsEditing(false)}>Cancel Edit</Button>
             )}
             <Button variant="danger" onClick={handleDelete} isLoading={saving}>Delete Ad</Button>
           </div>
        </div>

        <div className="p-6 space-y-6">
          {isEditing ? (
            <div className="space-y-6">
               <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                 <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Title</label>
                  <input 
                    type="text" 
                    value={editTitle} 
                    onChange={e => setEditTitle(e.target.value)} 
                    className="w-full border-gray-300 rounded-md shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border" 
                  />
                 </div>
                 <div>
                  <label className="block text-sm font-medium text-gray-700 mb-1">Price (RON)</label>
                  <input 
                    type="number" 
                    value={editPrice} 
                    onChange={e => setEditPrice(e.target.value)} 
                    className="w-full border-gray-300 rounded-md shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border" 
                  />
                 </div>
               </div>

               <div>
                  <label className="block text-sm font-medium text-gray-700 mb-2">Categories (Max based on plan)</label>
                  <div className="flex flex-wrap gap-2">
                    {PRODUCT_CATEGORIES.map((cat) => {
                      const isSelected = editCategories.includes(cat);
                      return (
                        <button
                          key={cat}
                          type="button"
                          onClick={() => toggleCategory(cat)}
                          className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-all ${
                            isSelected 
                              ? 'bg-indigo-600 text-white border-indigo-600 shadow-sm' 
                              : 'bg-white text-gray-700 border-gray-300 hover:border-indigo-300 hover:bg-gray-50'
                          }`}
                        >
                          {cat} {isSelected && '✓'}
                        </button>
                      );
                    })}
                  </div>
               </div>

               <div className="grid grid-cols-1 md:grid-cols-3 gap-4 bg-gray-50 p-4 rounded-lg border border-gray-100">
                 <div>
                   <label className="block text-xs font-bold text-gray-500 uppercase mb-1">County</label>
                   <select 
                      value={editCounty} 
                      onChange={e => {
                        setEditCounty(e.target.value);
                        setEditCity('');
                        setEditVillage('');
                      }} 
                      className="w-full border-gray-300 rounded-md text-sm p-2"
                   >
                     {getCounties().map(c => <option key={c} value={c}>{c}</option>)}
                   </select>
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-gray-500 uppercase mb-1">City/Commune</label>
                   <select 
                      value={editCity} 
                      onChange={e => {
                        setEditCity(e.target.value);
                        setEditVillage('');
                      }}
                      disabled={!editCounty}
                      className="w-full border-gray-300 rounded-md text-sm p-2 disabled:bg-gray-100"
                   >
                     <option value="">Select...</option>
                     {availableCities.map(c => <option key={c} value={c}>{c}</option>)}
                   </select>
                 </div>
                 <div>
                   <label className="block text-xs font-bold text-gray-500 uppercase mb-1">Village (Sat)</label>
                   <select 
                      value={editVillage} 
                      onChange={e => setEditVillage(e.target.value)}
                      disabled={!editCity}
                      className="w-full border-gray-300 rounded-md text-sm p-2 disabled:bg-gray-100"
                   >
                     <option value="">Select...</option>
                     {availableVillages.map(v => <option key={v} value={v}>{v}</option>)}
                   </select>
                 </div>
               </div>

               <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Phone Number</label>
                <input 
                  type="text" 
                  value={editPhone} 
                  onChange={e => setEditPhone(e.target.value)} 
                  className="w-full border-gray-300 rounded-md shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border" 
                />
               </div>

               <div>
                <label className="block text-sm font-medium text-gray-700 mb-1">Description</label>
                <textarea 
                  rows={5} 
                  value={editDesc} 
                  onChange={e => setEditDesc(e.target.value)} 
                  className="w-full border-gray-300 rounded-md shadow-sm focus:border-indigo-500 focus:ring-indigo-500 p-2 border" 
                />
               </div>

               <div className="flex justify-end space-x-3 pt-4 border-t border-gray-100">
                 <Button variant="outline" onClick={() => setIsEditing(false)}>Cancel</Button>
                 <Button onClick={handleSave} isLoading={saving}>Save Changes</Button>
               </div>
            </div>
          ) : (
            <div className="space-y-6">
              <div className="flex flex-col md:flex-row gap-6">
                 {/* Left Column: Image (Preview) */}
                 <div className="w-full md:w-1/3">
                    <div className="aspect-w-4 aspect-h-3 rounded-lg overflow-hidden bg-gray-100 border border-gray-200">
                      {ad.images[0] ? (
                        <img src={ad.images[0]} alt="Ad" className="object-cover w-full h-full" />
                      ) : (
                        <div className="flex items-center justify-center h-48 text-gray-400">No Image</div>
                      )}
                    </div>
                 </div>

                 {/* Right Column: Details */}
                 <div className="w-full md:w-2/3 space-y-4">
                    <div className="flex justify-between items-start">
                       <div>
                          <h3 className="text-xl font-bold text-gray-900">{ad.title}</h3>
                          <p className="text-2xl font-bold text-green-600 mt-1">{ad.price} RON</p>
                       </div>
                    </div>

                    <div className="flex flex-wrap gap-2">
                      {ad.categories.map(cat => (
                        <span key={cat} className="inline-flex items-center px-2.5 py-0.5 rounded-full text-xs font-medium bg-indigo-100 text-indigo-800">
                          {cat}
                        </span>
                      ))}
                    </div>

                    <div className="grid grid-cols-2 gap-4 text-sm text-gray-600 bg-gray-50 p-3 rounded-lg">
                       <div>
                         <span className="block text-xs font-bold text-gray-400 uppercase">Location</span>
                         {ad.location.city}, {ad.location.county} {ad.location.village && `(${ad.location.village})`}
                       </div>
                       <div>
                         <span className="block text-xs font-bold text-gray-400 uppercase">Contact</span>
                         {ad.phoneNumber}
                       </div>
                    </div>

                    <div>
                       <span className="block text-xs font-bold text-gray-400 uppercase mb-1">Description</span>
                       <p className="text-gray-700 whitespace-pre-wrap">{ad.description}</p>
                    </div>
                 </div>
              </div>
            </div>
          )}
        </div>

        <div className="bg-gray-50 px-6 py-4 border-t border-gray-200">
           <div className="flex items-center justify-between">
             <div className="text-sm text-gray-600">
               <span className="block font-medium">Boost your visibility?</span>
               Extend your ad duration or promote it to the homepage.
             </div>
             <Button variant="outline" onClick={handleRenew}>Renew Plan</Button>
           </div>
        </div>
      </div>
    </div>
  );
};
